/* ─────────────────────────────────────────────────────────────────
GENERAR ACUERDO PDF (BLINDADO CON TRAMPA DE ERRORES)
───────────────────────────────────────────────────────────────── */
/* ─────────────────────────────────────────────────────────────────
   GENERAR ACUERDO PDF (DISEÑO ROJO/DARK TIPO "UALÁ/ALAU")
   ───────────────────────────────────────────────────────────────── */
/* ─────────────────────────────────────────────────────────────────
   GENERAR ACUERDO PDF (DISEÑO BLANCO Y NARANJA - GALICIA)
   ───────────────────────────────────────────────────────────────── */
/* ─────────────────────────────────────────────────────────────────
   GENERAR ACUERDO PDF (DISEÑO BLANCO Y NARANJA - GALICIA)
   ───────────────────────────────────────────────────────────────── */
/* ─────────────────────────────────────────────────────────────────
   GENERAR ACUERDO PDF (DISEÑO GALICIA + TEXTO OFICIAL DEL BANCO)
   ───────────────────────────────────────────────────────────────── */
function generateAgreementPDF(cuotasOrData, planOrData) {
  try {
    const manualData = typeof cuotasOrData === "object" && cuotasOrData !== null ? cuotasOrData : null;
    
    // 1. LLAMADO SEGURO A LA LIBRERÍA
    const jsPDFConstructor = (window.jspdf && window.jspdf.jsPDF) ? window.jspdf.jsPDF : window.jsPDF;
    if (!jsPDFConstructor) {
      alert("⚠️ Error: La librería de PDFs no se cargó. Apretá F5 para recargar.");
      return;
    }

    const doc = new jsPDFConstructor({ orientation: "portrait", unit: "mm", format: "a4" });

    // Variables base
    const isManual = Boolean(manualData);
    const plan = isManual
      ? {
          label: manualData.cuotas === 1 ? "Emisión Manual 1 Pago" : `Emisión Manual ${manualData.cuotas} Pagos`,
          porcentaje: manualData.deudaOriginal > 0 ? Math.round((1 - (manualData.capitalAcordado * 1.242) / (manualData.deudaOriginal * 1.242)) * 100) : 0,
          hab: manualData.capitalAcordado * 0.16,
          had: manualData.capitalAcordado * 0.242,
          valorCuota: (manualData.capitalAcordado * 1.242) / manualData.cuotas,
        }
      : planOrData;

    const cuotas     = isManual ? parseInt(manualData.cuotas, 10) : cuotasOrData;
    const anticipoPDF = isManual ? (manualData.anticipo || null) : null;
    const deudaOriginal = isManual ? manualData.deudaOriginal : estadoActual.deuda;
    const montoFinal = isManual ? manualData.capitalAcordado : plan.montoRecuperar;
    const nombreDeudor = isManual ? manualData.nombre : estadoActual.nombre;
    const dniDeudor = isManual ? manualData.dni : estadoActual.dni;

    // Desglose oficial de Capital y Honorarios (Total / 1.242)
    const capitalBanco = montoFinal / 1.242;
    const honorariosAgencia = montoFinal - capitalBanco;

    const W = 210;
    const M = 20;
    
    const timestamp    = Date.now();
    const acuerdoID    = `GAL-${dniDeudor}-${String(Math.floor(Math.random() * 90000) + 10000)}`;
    const hoy          = new Date();
    const fechaEmision = hoy.toLocaleDateString("es-AR", { day: "2-digit", month: "long", year: "numeric" });

    // =================================================================
    // 1. ENCABEZADO (Naranja Galicia)
    // =================================================================
    doc.setFillColor(234, 88, 12); // Naranja
    doc.rect(0, 0, W, 36, "F");
    
    if (typeof LOGO_B64 !== 'undefined' && LOGO_B64.trim() !== "") {
      try { doc.addImage(LOGO_B64, "PNG", M, 4, 38, 28); } catch (e) {}
    }
    
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(11);
    doc.setFont("helvetica", "bold");
    doc.text("CERTIFICADO DE ACUERDO", W - M, 14, { align: "right" });
    
    doc.setFont("helvetica", "normal");
    doc.setFontSize(9);
    doc.setTextColor(255, 240, 230);
    doc.text("Buenos Aires, " + fechaEmision, W - M, 22, { align: "right" });

    doc.setFontSize(8);
    doc.setTextColor(255, 220, 200);
    doc.text("N° " + acuerdoID, W - M, 30, { align: "right" });

    let y = 46;

    // =================================================================
    // 2. BLOQUE 1: INTRODUCCIÓN Y TITULAR (Gris claro)
    // =================================================================
    doc.setFillColor(248, 250, 252);
    doc.setDrawColor(226, 232, 240);
    doc.setLineWidth(0.3);
    doc.roundedRect(M, y, W - M * 2, 34, 3, 3, "FD");
    
    doc.setTextColor(234, 88, 12);
    doc.setFontSize(8);
    doc.setFont("helvetica", "bold");
    doc.text("SITUACIÓN CREDITICIA DEL TITULAR", M + 6, y + 7);
    
    doc.setTextColor(15, 23, 42);
    doc.setFontSize(9);
    doc.text(`Nombre: ${(nombreDeudor || "-").toUpperCase()}   |   DNI: ${dniDeudor || "-"}`, M + 6, y + 13);
    
    doc.setFont("helvetica", "normal");
    doc.setTextColor(71, 85, 105);
    const textoIntro = `Por medio de la presente informamos a Uds. que el/la Sr./Sra. ${(nombreDeudor || "-").toUpperCase()} con DNI: ${dniDeudor} registra una deuda con Banco Galicia y Buenos Aires S.A.U. que se encuentra en mora y a la fecha su saldo es de ${formatARS(deudaOriginal)}.-`;
    const linesIntro = doc.splitTextToSize(textoIntro, W - M * 2 - 12);
    doc.text(linesIntro, M + 6, y + 20);
    
    y += 38;

    // =================================================================
    // 3. BLOQUE PRODUCTOS INCLUIDOS EN EL ACUERDO
    // =================================================================
    const productosRaw = isManual
      ? (manualData.productos || [{ tipo: "Honorarios de Gestión Extrajudicial", numero: "Estudio CO-RE" }])
      : (estadoActual.productos || [{ tipo: "Honorarios de Gestión Extrajudicial", numero: "Estudio CO-RE" }]);
    // Límite de 5 productos para que el PDF entre en una página A4
    const productos = productosRaw.slice(0, 5);
    if (productosRaw.length > 5) {
      console.warn("PDF: se muestran solo los primeros 5 productos para mantener el formato en una página.");
    }

    const alturaProductos = 12 + productos.length * 6 + 4;
    doc.setFillColor(248, 250, 252);
    doc.setDrawColor(226, 232, 240);
    doc.setLineWidth(0.3);
    doc.roundedRect(M, y, W - M * 2, alturaProductos, 3, 3, "FD");

    doc.setTextColor(234, 88, 12);
    doc.setFontSize(8);
    doc.setFont("helvetica", "bold");
    doc.text("PRODUCTOS INCLUIDOS EN EL ACUERDO", M + 6, y + 8);

    doc.setFont("helvetica", "normal");
    doc.setTextColor(15, 23, 42);
    let py = y + 12;
    productos.forEach((p, i) => {
      const label = p.numero && p.numero !== "Estudio CO-RE"
        ? `${String(i + 1).padStart(2, "0")}. ${p.tipo}  —  N° ${p.numero}`
        : `${String(i + 1).padStart(2, "0")}. ${p.tipo}${p.numero ? "  —  " + p.numero : ""}`;
      doc.setFontSize(8);
      if (p.tipo === "Honorarios de Gestión Extrajudicial") {
        doc.setTextColor(100, 116, 139);
        doc.setFont("helvetica", "italic");
      } else {
        doc.setTextColor(15, 23, 42);
        doc.setFont("helvetica", "normal");
      }
      doc.text(label, M + 8, py);
      py += 6;
    });

    y += alturaProductos + 4;

    // =================================================================
    // 3. BLOQUE 2: FORMA DE PAGO
    // =================================================================
    // Datos para la cadena de cálculo
    const deudaOrigPDF  = isManual ? (manualData.deudaOriginal || montoFinal) : estadoActual.deuda;
    const baseConHon    = deudaOrigPDF * 1.242;
    const montoQuitaPDF = baseConHon - montoFinal;
    const pctQuitaPDF   = Math.round((montoQuitaPDF / baseConHon) * 100);

    doc.setFillColor(248, 250, 252);
    doc.setDrawColor(226, 232, 240);
    doc.roundedRect(M, y, W - M * 2, anticipoPDF ? 64 : (cuotas > 1 ? 57 : 50), 3, 3, "FD");

    doc.setTextColor(234, 88, 12);
    doc.setFontSize(8);
    doc.setFont("helvetica", "bold");
    doc.text("CONDICIONES DEL ACUERDO — DETALLE DEL CÁLCULO", M + 6, y + 7);

    // Cadena de cálculo
    const col1 = M + 6;
    const col2 = W - M - 6;
    doc.setFontSize(8);

    // Fila 1: Deuda original
    doc.setFont("helvetica", "normal");
    doc.setTextColor(100, 116, 139);
    doc.text("Deuda original registrada:", col1, y + 14);
    doc.setTextColor(15, 23, 42);
    doc.setFont("helvetica", "bold");
    doc.text(formatARS(deudaOrigPDF), col2, y + 14, { align: "right" });

    // Fila 2: + Honorarios
    doc.setFont("helvetica", "normal");
    doc.setTextColor(100, 116, 139);
    doc.text("+ Honorarios e IVA (24,2%):", col1, y + 20);
    doc.setTextColor(15, 23, 42);
    doc.setFont("helvetica", "bold");
    doc.text("+ " + formatARS(baseConHon - deudaOrigPDF), col2, y + 20, { align: "right" });

    // Separador delgado
    doc.setDrawColor(200, 210, 220);
    doc.setLineWidth(0.2);
    doc.line(col1, y + 23, col2, y + 23);

    // Fila 3: Base de cálculo
    doc.setFont("helvetica", "bold");
    doc.setTextColor(30, 64, 175); // azul
    doc.text("Base de cálculo:", col1, y + 28);
    doc.text(formatARS(baseConHon), col2, y + 28, { align: "right" });

    // Fila 4: Quita
    doc.setFont("helvetica", "normal");
    doc.setTextColor(100, 116, 139);
    doc.text(`− Quita aplicada (${pctQuitaPDF}%):`, col1, y + 34);
    doc.setFont("helvetica", "bold");
    doc.setTextColor(220, 38, 38); // rojo
    doc.text("- " + formatARS(montoQuitaPDF), col2, y + 34, { align: "right" });

    // Separador
    doc.setDrawColor(200, 210, 220);
    doc.setLineWidth(0.2);
    doc.line(col1, y + 37, col2, y + 37);

    // Fila 5: Total a pagar
    doc.setFont("helvetica", "bold");
    doc.setTextColor(22, 163, 74); // verde
    doc.text("TOTAL A PAGAR:", col1, y + 43);
    doc.text(formatARS(montoFinal), col2, y + 43, { align: "right" });

    // Detalle de cuotas / anticipo
    if (anticipoPDF) {
      doc.setFont("helvetica", "normal");
      doc.setTextColor(15, 23, 42);
      doc.setFontSize(8);
      doc.text(`Anticipo: ${formatARS(anticipoPDF.anticipo)}   |   Saldo: ${formatARS(anticipoPDF.saldo)}`, col1, y + 51);
      doc.text(`${anticipoPDF.nCuotas} cuota/s del saldo de ${formatARS(anticipoPDF.cuotaValor)} c/u`, col1, y + 57);
      y += 65;
    } else if (cuotas > 1) {
      doc.setFont("helvetica", "normal");
      doc.setTextColor(15, 23, 42);
      doc.setFontSize(8);
      doc.text(
        `${cuotas} cuotas de ${formatARS(plan.valorCuota)} c/u   |   1ª cuota estimada: ${calcularVencimiento48hs()}`,
        col1, y + 51
      );
      y += 62;
    } else {
      y += 55;
    }

    // =================================================================
    // 4. BLOQUE 3: DATOS PARA EL PAGO (Borde Naranja)
    // =================================================================
    doc.setFillColor(255, 255, 255);
    doc.setDrawColor(234, 88, 12);
    doc.setLineWidth(0.5);
    doc.roundedRect(M, y, W - M * 2, 68, 3, 3, "FD");
    
    doc.setTextColor(234, 88, 12);
    doc.setFontSize(8);
    doc.setFont("helvetica", "bold");
    doc.text("DATOS PARA EL PAGO — TRANSFERENCIA BANCARIA OBLIGATORIA", M + 6, y + 8);
    
    doc.setFont("helvetica", "normal");
    doc.setTextColor(71, 85, 105);
    const textoAclaracion = "El mencionado importe cancelatorio es por TODO CONCEPTO, incluyendo cancelación de deuda y de los honorarios. Se deberán realizar 2 operaciones según detalle:";
    const linesAclaracion = doc.splitTextToSize(textoAclaracion, W - M * 2 - 12);
    doc.text(linesAclaracion, M + 6, y + 14);

    let subY = y + 27;

    // --- Cuenta 1: Banco ---
    doc.setTextColor(15, 23, 42);
    doc.setFontSize(8.5);
    doc.setFont("helvetica", "bold");
    doc.text(`1. PAGO PARA Banco Galicia y Buenos Aires S.A.U.   |   IMPORTE: ${formatARS(capitalBanco)}`, M + 6, subY);
    
    doc.setTextColor(100, 116, 139);
    doc.setFont("helvetica", "normal");
    doc.text("Titular: MARIA VALERIA FANDIÑO   |   CUIT 27-20481581-5", M + 6, subY + 5);
    doc.text(`CBU: ${CUENTAS.recaudacion.cbu}   |   ALIAS: ${CUENTAS.recaudacion.alias}`, M + 6, subY + 10);

    subY += 22;

    // --- Cuenta 2: Honorarios ---
    doc.setTextColor(15, 23, 42);
    doc.setFont("helvetica", "bold");
    doc.text(`2. PAGO DE HONORARIOS   |   IMPORTE: ${formatARS(honorariosAgencia)}`, M + 6, subY);
    
    doc.setTextColor(100, 116, 139);
    doc.setFont("helvetica", "normal");
    doc.text("Titular: MARIA VALERIA FANDIÑO   |   CUIT 27-20481581-5", M + 6, subY + 5);
    doc.text(`CBU: ${CUENTAS.honorarios.cbu}   |   ALIAS: ${CUENTAS.honorarios.alias}`, M + 6, subY + 10);

    y += 73;

    // =================================================================
    // 5. BLOQUE 4: CIERRE Y CERTIFICADO
    // =================================================================
    doc.setFillColor(248, 250, 252);
    doc.setDrawColor(226, 232, 240);
    doc.setLineWidth(0.3);
    doc.roundedRect(M, y, W - M * 2, 28, 3, 3, "FD");
    
    doc.setTextColor(234, 88, 12);
    doc.setFontSize(8);
    doc.setFont("helvetica", "bold");
    doc.text("ACREDITACIÓN Y CERTIFICADO", M + 6, y + 7);
    
    doc.setFont("helvetica", "normal");
    doc.setTextColor(71, 85, 105);
    const textoCierre = "UNA VEZ REALIZADOS LOS PAGOS DEBEN ENVIAR AMBOS COMPROBANTES A LA CASILLA: cobranzasgalicia@co-re.com.ar.\n\nEl certificado de cancelación de los productos mencionados será emitido por el Estudio a los 15 días de efectivizados los pagos.";
    const linesCierre = doc.splitTextToSize(textoCierre, W - M * 2 - 12);
    doc.text(linesCierre, M + 6, y + 13);
    
    y += 33;

    // =================================================================
    // 6. FIRMAS
    // =================================================================
    const lineaY = y;
    const inicioDerecha = W - M - 60;

    doc.setDrawColor(148, 163, 184);
    doc.setLineWidth(0.3);
    doc.line(inicioDerecha, lineaY, W - M, lineaY);

    doc.setTextColor(234, 88, 12);
    doc.setFontSize(9);
    doc.setFont('helvetica', 'bold');
    doc.text('María Valeria Fandiño', inicioDerecha, lineaY + 5);

    doc.setFontSize(7);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(100, 116, 139);
    doc.text('Apoderada', inicioDerecha, lineaY + 9);
    doc.text('Estudio CO-RE | Banco Galicia', inicioDerecha, lineaY + 13);

    doc.setTextColor(148, 163, 184);
    doc.setFontSize(7.5);
    doc.text("Firma Autorizada", inicioDerecha, lineaY - 2);

    // =================================================================
    // 7. PIE DE PÁGINA
    // =================================================================
    doc.setFillColor(234, 88, 12);
    doc.rect(0, 282, W, 15, "F");
    
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(7);
    doc.text(`CO-RE | Collection. Recovery | N° ${acuerdoID} | Documento oficial`, W / 2, 289, { align: "center" });

    // Guardar
    doc.save(`Acuerdo_${(nombreDeudor || "Deudor").replace(/\s+/g, "_")}_${cuotas}Pagos.pdf`);
    mostrarToast("📄 Acuerdo generado (Formato Oficial Galicia)", "success");

  } catch (error) {
    alert("❌ Error interno al generar el PDF:\n" + error.message);
    console.error(error);
  }
}

/* ─────────────────────────────────────────────────────────────────
   INPUT FORMATTERS
   ───────────────────────────────────────────────────────────────── */
function initInputFormatters() {
  const inputDeuda = document.getElementById("inputDeuda");
  if (!inputDeuda) return;

  inputDeuda.addEventListener("blur", (e) => {
    let val = parsearNumero(e.target.value);
    if (!isNaN(val)) {
      e.target.value = new Intl.NumberFormat("es-AR", {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2
      }).format(val);
    }
  });
}

/* ─────────────────────────────────────────────────────────────────
   INPUT: Solo números en DNI
   ───────────────────────────────────────────────────────────────── */
function initDniInput() {
  const inputDni = document.getElementById("inputDni");
  if (!inputDni) return;

  inputDni.addEventListener("keypress", (e) => {
    if (!/\d/.test(String.fromCharCode(e.which))) e.preventDefault();
  });
}

/* ─────────────────────────────────────────────────────────────────
   INICIALIZACIÓN
   ───────────────────────────────────────────────────────────────── */
document.addEventListener("DOMContentLoaded", () => {
  // Mostrar sección inicial
  navigateTo("calculadora");

  // Inicializar formatters
  initInputFormatters();
  initDniInput();

  // Crear overlay para menú móvil
  getOrCreateOverlay();

  // Inicializar listeners de emisión manual
  initManualListeners();

  // Enter en el formulario lanza el cálculo
  // Live preview listeners
  document.getElementById("inputDeuda")?.addEventListener("input", actualizarLivePreview);

  ["inputDni", "inputNombre", "inputDeuda"].forEach((id) => {
    const el = document.getElementById(id);
    if (el) {
      el.addEventListener("keydown", (e) => {
        if (e.key === "Enter") calcularAuto();
        document.getElementById("inputMontoCliente")?.addEventListener("keydown", (e) => {
          if (e.key === "Enter") calcularAuto();
        });
      });
    }
  });

  console.log("%c⬡ Estudio CO-RE — Panel de Cobranzas v2.0", "color:#ea580c;font-weight:bold;font-size:14px");
});